from typing import List

class Solution:
    def matrixSum(self, nums: List[List[int]]) -> int:
        # Sort each row descending; then repeatedly take the max available across rows
        rows = [sorted(row, reverse=True) for row in nums]
        max_cols = max(len(row) for row in rows)
        score = 0

        # At each step k, the k-th largest element of each row is available if it exists.
        # The removed set's maximum is exactly the maximum among those available elements.
        for k in range(max_cols):
            best = None
            for row in rows:
                if k < len(row):
                    val = row[k]
                    if best is None or val > best:
                        best = val
            # best must exist because matrix is not empty at this k
            if best is not None:
                score += best

        return score
