from typing import List

class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        nums = [0] * n
        ans = []
        same = 0  # number of adjacent pairs with same non-zero color

        for idx, col in queries:
            # If we have an existing color at idx, remove its contribution to pairs (idx-1, idx) and (idx, idx+1)
            if nums[idx] != 0:
                c = nums[idx]
                if idx - 1 >= 0 and nums[idx - 1] == c:
                    same -= 1
                if idx + 1 < n and nums[idx + 1] == c:
                    same -= 1

