class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        nums = [0] * n
        ans = [0] * len(queries)
        cur = 0  # current number of adjacent equal colored pairs (excluding zeros)

        def dec_if_equal(i: int):
            """If i and i+1 form an equal non-zero pair, decrement cur."""
            nonlocal cur
            if nums[i] != 0 and nums[i] == nums[i + 1]:
                cur -= 1

        def inc_if_equal(i: int):
            """If i and i+1 form an equal non-zero pair, increment cur."""
            nonlocal cur
            if nums[i] != 0 and nums[i] == nums[i + 1]:
                cur += 1

        for k, (idx, color) in enumerate(queries):
            # Remove contributions of pairs that may change: (idx-1, idx) and (idx, idx+1)
            if idx - 1 >= 0:
                dec_if_equal(idx - 1)
            if idx + 1 < n:
                dec_if_equal(idx)

            nums[idx] = color

            # Add contributions after update
            if idx - 1 >= 0:
                inc_if_equal(idx - 1)
            if idx + 1 < n:
                inc_if_equal(idx)

            ans[k] = cur

        return ans
