    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)
        if n == 1:
            return True

        # If any number is 1, it can't connect to any other (gcd(1, x) == 1 always).
        for x in nums:
            if x == 1:
                return False

        # Build graph connectivity via common prime factors:
        # Union indices that share any prime factor.
        parent = list(range(n))
        rank = [0] * n

        def find(a: int) -> int:
            while parent[a] != a:
                parent[a] = parent[parent[a]]
                a = parent[a]
            return a

        def union(a: int, b: int) -> None:
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                parent[ra] = rb
            elif rank[ra] > rank[rb]:
                parent[rb] = ra
            else:
                parent[rb] = ra
                rank[ra] += 1

        # Sieve smallest prime factor up to max(nums)
        maxv = max(nums)
        spf = list(range(maxv + 1))
        for i in range(2, int(maxv ** 0.5) + 1):
            if spf[i] == i:  # i is prime
                step = i
                start = i * i
                for j in range(start, maxv + 1, step):
                    if spf[j] == j:
                        spf[j] = i

        # prime_to_index maps prime factor -> first index containing that factor
        prime_to_index = {}

        def factor_distinct(x: int) -> List[int]:
            res = []
            while x > 1:
                p = spf[x]
                res.append(p)
                while x % p == 0:
                    x //= p
            return res

        for i, x in enumerate(nums):
            primes = factor_distinct(x)
            for p in primes:
                if p in prime_to_index:
                    union(i, prime_to_index[p])
                else:
                    prime_to_index[p] = i

        root0 = find(0)
        for i in range(1, n):
            if find(i) != root0:
                return False
        return True
