        n = len(nums)
        if n <= 2:
            # With 0-indexed indices, if n<=2 and there exists at least one pair:
            # For n==1, trivially true; for n==2, traversable iff gcd>1.
            if n == 1:
                return True
            return gcd(nums[0], nums[1]) > 1

        # If any element is 1, it cannot connect to anything (since gcd(1, x)=1).
        if any(x == 1 for x in nums):
            return False

        # Build connections via prime factors and union indices' connectivity.
        # Idea: Two indices are connected iff they share at least one prime factor.
        # If the overall graph is connected, then every pair can reach each other.
        parent = list(range(n))
        size = [1] * n

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if size[ra] < size[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            size[ra] += size[rb]

        # Sieve for smallest prime factor up to max(nums)
        m = max(nums)
        spf = list(range(m + 1))
        for i in range(2, int(m**0.5) + 1):
            if spf[i] == i:  # prime
                step = i
                start = i * i
                for j in range(start, m + 1, step):
                    if spf[j] == j:
                        spf[j] = i

        def prime_factors_distinct(x):
            res = []
            while x > 1:
                p = spf[x]
                res.append(p)
                while x % p == 0:
                    x //= p
            return res

        # Map each prime factor to the first index that has it.
        prime_to_index = {}
        for i, x in enumerate(nums):
            for p in prime_factors_distinct(x):
                if p in prime_to_index:
                    union(i, prime_to_index[p])
                else:
                    prime_to_index[p] = i

        # Check if all indices are in the same connected component.
        root = find(0)
        return all(find(i) == root for i in range(1, n))
