class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)
        if n == 1:
            return True

        # If there is a number equal to 1, it has no common factor > 1 with any other number,
        # so it cannot connect to others. Then not all pairs are traversable.
        for x in nums:
            if x == 1:
                return False

        # Build graph over prime factors: connect indices that share a prime factor.
        # Two indices are connected iff their numbers share a prime factor > 1 (directly or via chain).
        prime_to_first_idx = {}
        primes_needed = set()

        def factorize(x: int) -> List[int]:
            res = []
            d = 2
            while d * d <= x:
                if x % d == 0:
                    res.append(d)
                    while x % d == 0:
                        x //= d
                d += 1 if d == 2 else 2  # small speedup: check 2 then odd numbers
            if x > 1:
                res.append(x)
            return res

        # Collect prime factors and record for each prime one representative index
        for i, val in enumerate(nums):
            pf = factorize(val)
            for p in pf:
                primes_needed.add(p)
                if p not in prime_to_first_idx:
                    prime_to_first_idx[p] = i

        # Build edges between indices via shared primes:
        # Instead of O(n^2), we connect each index to representative indices of its prime factors.
        adj = [[] for _ in range(n)]
        for i, val in enumerate(nums):
            pf = factorize(val)
            for p in pf:
                j = prime_to_first_idx[p]
                if j != i:
                    adj[i].append(j)
                    adj[j].append(i)

        # Graph is undirected; check connectivity of indices.
        seen = [False] * n
        q = deque([0])
        seen[0] = True
        cnt = 1
        while q:
            u = q.popleft()
            for v in adj[u]:
                if not seen[v]:
                    seen[v] = True
                    cnt += 1
                    q.append(v)

        return cnt == n
