        n = len(nums)

        # Indices with value 1 cannot connect to anything (gcd(1, x) = 1 for all x)
        if any(x == 1 for x in nums):
            return False

        # Union-Find over prime factors
        parent = list(range(100001))
        rank = [0] * 100001

        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a: int, b: int) -> None:
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                parent[ra] = rb
            elif rank[ra] > rank[rb]:
                parent[rb] = ra
            else:
                parent[rb] = ra
                rank[ra] += 1

        # Sieve smallest prime factor up to 1e5
        MAXV = 100000
        spf = list(range(MAXV + 1))
        for i in range(2, int(MAXV ** 0.5) + 1):
            if spf[i] == i:  # prime
                step = i
                start = i * i
                for j in range(start, MAXV + 1, step):
                    if spf[j] == j:
                        spf[j] = i

        def factorize(x: int) -> List[int]:
            res = []
            while x > 1:
                p = spf[x]
                res.append(p)
                while x % p == 0:
                    x //= p
            return res

        # Connect prime factors within each number to its first factor
        used_primes = set()
        for x in nums:
            primes = factorize(x)
            if not primes:
                continue
            first = primes[0]
            used_primes.add(first)
            for p in primes[1:]:
                used_primes.add(p)
                union(first, p)

        # Ensure all used primes belong to a single connected component
        it = iter(used_primes)
        root = find(next(it))
        for p in it:
            if find(p) != root:
                return False
        return True
