        if any(x == 1 for x in nums):
            return False

        # Build DSU over prime factors seen in the array (standard approach).
        parent = {}
        rank = defaultdict(int)

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                parent[ra] = rb
            elif rank[ra] > rank[rb]:
                parent[rb] = ra
            else:
                parent[rb] = ra
                rank[ra] += 1

        def add(x):
            if x not in parent:
                parent[x] = x

        # Factorization (spf sieve up to 1e5)
        maxv = max(nums)
        spf = list(range(maxv + 1))
        for i in range(2, int(maxv ** 0.5) + 1):
            if spf[i] == i:
                step = i
                start = i * i
                for j in range(start, maxv + 1, step):
                    if spf[j] == j:
                        spf[j] = i

        def prime_factors(x):
            res = []
            while x > 1:
                p = spf[x]
                res.append(p)
                while x % p == 0:
                    x //= p
            return res

        # For each number, connect its prime factors together.
        # Ensures that indices sharing a prime factor fall into one component.
        first_factor_of_component = None
        for x in nums:
            factors = prime_factors(x)
            # Remove duplicates not needed since prime_factors returns distinct primes due to division loop.
            if not factors:
                return False
            for f in factors:
                add(f)
            base = factors[0]
            for f in factors[1:]:
                union(base, f)

        # Check if all primes appear in a single connected component
        # (If every number has factors and all factor-sets connect, then all indices are connected.)
        primes = list(parent.keys())
        if not primes:
            return True

        root = find(primes[0])
        for p in primes[1:]:
            if find(p) != root:
                return False
        return True
