from bisect import bisect_left, bisect_right

class Solution:
    def countServers(self, n: int, logs: List[List[int]], x: int, queries: List[int]) -> List[int]:
        # Group log times by server_id
        times_by_server = [[] for _ in range(n)]
        for sid, t in logs:
            times_by_server[sid - 1].append(t)

        # Sort each server's times for binary search
        for s in range(n):
            if times_by_server[s]:
                times_by_server[s].sort()

        ans = []
        # For each query, count servers having at least one log in [q-x, q]
        for q in queries:
            start = q - x
            end = q
            used = 0
            for s in range(n):
                ts = times_by_server[s]
                if not ts:
                    continue
                # Check if there's any time in [start, end]
                i = bisect_left(ts, start)
                if i < len(ts) and ts[i] <= end:
                    used += 1
            ans.append(n - used)

        return ans
