from typing import List
from bisect import bisect_right

class Solution:
    def countServers(self, n: int, logs: List[List[int]], x: int, queries: List[int]) -> List[int]:
        # Collect times per server
        times = [[] for _ in range(n)]
        for sid, t in logs:
            times[sid - 1].append(t)

        # Sort times for each server
        for i in range(n):
            if times[i]:
                times[i].sort()

        def server_has_request(sid_times: List[int], left: int, right: int) -> bool:
            # True if there exists time in [left, right]
            idx = bisect_right(sid_times, right)
            # Any element <= right, check if the last <= right is >= left
            return idx > 0 and sid_times[idx - 1] >= left

        res = []
        for q in queries:
            left = q - x
            right = q
            zero_count = 0
            for i in range(n):
                if not times[i]:  # no logs at all
                    zero_count += 1
                else:
                    if not server_has_request(times[i], left, right):
                        zero_count += 1
            res.append(zero_count)
        return res
