from typing import List

class Solution:
    def relocateMarbles(self, nums: List[int], moveFrom: List[int], moveTo: List[int]) -> List[int]:
        # Track how each original position's marbles map after all moves.
        # movemap[x] = latest destination position for marbles currently at x.
        movemap = {}
        for a, b in zip(moveFrom, moveTo):
            movemap[a] = b

        # Compress chain: if we move from a to b and later b moves to c, marbles end at c.
        def resolve(x: int) -> int:
            path = []
            while x in movemap and movemap[x] != x:
                path.append(x)
                x = movemap[x]
            # If we reached a point without mapping, x is final.
            # Path compression: map all visited nodes to final x.
            for node in path:
                movemap[node] = x
            return x

        occupied = set()
        for p in nums:
            final_pos = resolve(p)
            occupied.add(final_pos)

        return sorted(occupied)
