from typing import List

class Solution:
    def checkArray(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        diff = [0] * (n + 1)  # difference array for the active decrements
        dec = 0  # current total decrement applied to position i
        for i in range(n):
            dec += diff[i]

            # If current value becomes negative (i.e., needs more decrements than allowed), fail
            if nums[i] < dec:
                return False

            need = nums[i] - dec  # extra times we must apply operation starting at i
            if need:
                if i + k > n:
                    return False
                dec += need
                diff[i + k] -= need  # effect ends after k positions
        return True
```

