from typing import List

class Solution:
    def longestValidSubstring(self, word: str, forbidden: List[str]) -> int:
        # Collect forbidden patterns by length for O(1) checks over a bounded window.
        forb_by_len = {}
        max_len = 0
        for f in forbidden:
            L = len(f)
            forb_by_len.setdefault(L, set()).add(f)
            if L > max_len:
                max_len = L

        n = len(word)
        # Maintain sliding window [left, right] such that no forbidden substring ends within it.
        left = 0
        ans = 0

        # For each right, only need to inspect suffixes of lengths up to max_len (<= 10).
        for right in range(n):
            for L, patterns in forb_by_len.items():
                start = right - L + 1
                if start < left:
                    continue
                if start >= 0:
                    sub = word[start:right + 1]
                    if sub in patterns:
                        # If a forbidden substring ends at right, the valid window must start after it.
                        left = start + 1
            ans = max(ans, right - left + 1)

        return ans
