            roundedAmount = (purchaseAmount // 10) * 10
        elif remainder > 5:
            roundedAmount = (purchaseAmount // 10 + 1) * 10
        else:
            # remainder == 5: tie between current multiple and next multiple; choose larger
            roundedAmount = (purchaseAmount // 10 + 1) * 10

        return 100 - roundedAmount
