class Solution:
    def furthestDistanceFromOrigin(self, moves: str) -> int:
        x = 0
        far = 0
        for ch in moves:
            if ch == 'L' or ch == '_':
                x -= 1
            else:  # 'R'
                x += 1
            if x < far:  # farthest from origin on the negative side
                far = x
        return max(abs(far), abs(x if far == 0 else far))
