from typing import List

class Solution:
    def minProcessingTime(self, processorTime: List[int], tasks: List[int]) -> int:
        n = len(processorTime)
        # tasks.length == 4*n
        tasks_sorted = sorted(tasks)
        processors_sorted = sorted(processorTime)

        # Feasibility check for a given time T:
        # Each processor can take up to 4 tasks; a processor at start time p
        # can execute tasks with duration <= T - p.
        def can(T: int) -> bool:
            idx = len(tasks_sorted) - 1  # take largest remaining task each time
            for p in processors_sorted:
                if idx < 0:
                    return True
                limit = T - p
                if limit < 0:
                    continue

                # If current processor cannot finish the largest remaining task, skip it.
                if tasks_sorted[idx] > limit:
                    continue

                # Assign up to 4 largest tasks that fit
                cnt = 0
                while idx >= 0 and cnt < 4 and tasks_sorted[idx] <= limit:
                    idx -= 1
                    cnt += 1

                if idx < 0:
                    return True
            return idx < 0

        # Binary search answer
        low, high = 0, 10**18
        while low < high:
            mid = (low + high) // 2
            if can(mid):
                high = mid
            else:
                low = mid + 1
        return low
