class Solution:
    def minChanges(self, s: str) -> int:
        n = len(s)
        # Try both target patterns for "blocks of pairs":
        # Pattern A: even indices (0-based) are '0' and odd indices are '1'  => "0101..."
        # Pattern B: even indices are '1' and odd indices are '0'            => "1010..."
        #
        # Why this works:
        # Any beautiful string can be partitioned into substrings of even length
        # with all same bits. Equivalently, the string must be made of runs where
        # each run length is even. That implies adjacent bits differ only at
        # boundaries of runs; in a binary string with all run lengths even,
        # bits at indices with the same parity are constant within the string.
        # Thus the target must be either 0101... or 1010... (two global parity assignments),
        # and we minimize Hamming distance to one of them.

        mismatches_a = 0  # target: even='0', odd='1'
        mismatches_b = 0  # target: even='1', odd='0'

        for i, ch in enumerate(s):
            if (i % 2) == 0:
                # even index expected for pattern A is '0', for pattern B is '1'
                if ch != '0':
                    mismatches_a += 1
                if ch != '1':
                    mismatches_b += 1
            else:
                # odd index expected for pattern A is '1', for pattern B is '0'
                if ch != '1':
                    mismatches_a += 1
                if ch != '0':
                    mismatches_b += 1

        return min(mismatches_a, mismatches_b)
