    def distributeCandies(self, n: int, limit: int) -> int:
        ans = 0
        # Let allocations be (a, b, c) with a+b+c = n and 0 <= each <= limit
        for a in range(0, limit + 1):
            # b can range so that c = n-a-b is within [0, limit]
            low_b = max(0, n - a - limit)
