            cur = q.popleft()
            if cur == y:
                return dist[cur]

            d = dist[cur] + 1

            # increment/decrement
            if cur + 1 <= MAX and dist[cur + 1] == -1:
                dist[cur + 1] = d
                q.append(cur + 1)
            if cur - 1 >= 0 and dist[cur - 1] == -1:
                dist[cur - 1] = d
                q.append(cur - 1)

            # divides
            if cur % 11 == 0:
                nxt = cur // 11
                if nxt <= MAX and dist[nxt] == -1:
