        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            ch = s[i]
            runs[ch] = runs.get(ch, []) + [j - i]
            i = j

        def can(L: int) -> bool:
            if L == 0:
                return True
            for ch_runs in runs.values():
                total = 0
                for r in ch_runs:
                    if r >= L:
                        total += r - L + 1
                        if total >= 3:
                            return True
            return False

        # Max possible L is n
        lo, hi = 1, n
        ans = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if can(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans
