from typing import List

class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Trie built from arr1, then walk with each number in arr2
        # to find the maximum common prefix length.

        class Node:
            __slots__ = ("child", "cnt")
            def __init__(self):
                self.child = {}
                self.cnt = 0  # how many arr1 numbers pass through this node

        root = Node()

        def add(s: str):
            node = root
            for ch in s:
                if ch not in node.child:
                    node.child[ch] = Node()
                node = node.child[ch]
                node.cnt += 1

        def walk(s: str) -> int:
            node = root
            best = 0
            for i, ch in enumerate(s, start=1):
                nxt = node.child.get(ch)
                if nxt is None:
                    break
                best = i
                node = nxt
            return best

        # If we just take best while walking, we must ensure there exists at least
        # one arr1 number with that prefix. Since trie only stores arr1 paths,
        # every visited node implies existence.
        # Hence walk gives the length of the longest prefix between this s and
        # some arr1 number.
        for x in arr1:
            add(str(x))

        ans = 0
        for y in arr2:
            ans = max(ans, walk(str(y)))

        return ans
