        for num in arr1:
            s = str(num)
            node = 0
            for ch in s:
                if ch not in trie[node]:
                    trie[node][ch] = next_id
                    trie[next_id] = {}
                    next_id += 1
                node = trie[node][ch]

        best = 0

        # For each number in arr2, walk the trie and track longest path match
        for num in arr2:
            s = str(num)
            node = 0
            cur = 0
            for ch in s:
                nxt = trie[node].get(ch)
                if nxt is None:
                    break
                node = nxt
                cur += 1
            if cur > best:
                best = cur

        return best
