import sys
from itertools import permutations

def differs_by_one(a: str, b: str) -> bool:
    # True iff exactly one character differs
    cnt = 0
    for x, y in zip(a, b):
        if x != y:
            cnt += 1
            if cnt > 1:
                return False
    return cnt == 1

def solve():
    input_data = sys.stdin.read().strip().split()
    if not input_data:
        return
    it = iter(input_data)
    N = int(next(it))
    M = int(next(it))
    S = [next(it) for _ in range(N)]

    # Build adjacency based on "exactly one character differs"
    adj = [[False]*N for _ in range(N)]
    for i in range(N):
        for j in range(N):
            if i != j:
                adj[i][j] = differs_by_one(S[i], S[j])

    # Backtracking / DP over subsets to find Hamiltonian path in this directed graph
    # N <= 8 so bitmask DP is easy.
    FULL = (1 << N) - 1
    dp = [ [False]*N for _ in range(1 << N) ]
    # Start at any node
    for i in range(N):
        dp[1 << i][i] = True

    for mask in range(1 << N):
        for last in range(N):
            if not dp[mask][last]:
                continue
            for nxt in range(N):
                if mask & (1 << nxt):
                    continue
                if adj[last][nxt]:
                    dp[mask | (1 << nxt)][nxt] = True

    ok = any(dp[FULL][last] for last in range(N))
    print("Yes" if ok else "No")

if __name__ == "__main__":
