                    diff += 1
                    if diff > 1:
                        break
            if diff == 1:
                adj[i].append(j)

    full_mask = (1 << N) - 1

    @lru_cache(None)
    def dp(mask, last):
        # can we arrange strings in 'mask' ending at 'last' in a valid chain?
        if mask == (1 << last):
            return True
        pmask = mask ^ (1 << last)
        # try predecessor p such that p -> last and p in pmask
        for p in range(N):
            if (pmask >> p) & 1:
                # p must connect to last
                # check quickly by membership
                if last in adj[p]:
                    if dp(pmask, p):
                        return True
        return False

    for start in range(N):
        if dp(1 << start, start) and N == 1:
            print("Yes")
            return

    for last in range(N):
        if dp(full_mask, last):
            print("Yes")
            return
    print("No")

